#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
typedef long long ll;
inline ll read()
{
	ll res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}

const int N=2510;vector<int> G[N],T[N];
int n,m,K,dis[N],que[N];ll a[N];bool w[N][N];
int f1[N],f2[N],f3[N];
inline void bfs(int s)
{
	memset(dis,0,sizeof(dis));
	int H,T;dis[que[H=T=0]=s]=1;
	while(H<=T)
	{
		int u=que[H++];
		for(int v:G[u])if(!dis[v])
		{
			dis[v]=dis[u]+1;
			que[++T]=v;
		}
	}
	rep(1,n,i)w[s][i]=(dis[i]&&dis[i]<=K);
}
int main()
{
	n=read();m=read();K=read()+2;
	rep(2,n,i)a[i]=read();
	rep(1,m,i)
	{
		int x=read(),y=read();
		G[x].push_back(y);
		G[y].push_back(x);
	}
	rep(1,n,i)bfs(i);
	rep(2,n,i)
	{
		rep(2,n,k)if(k!=i&&w[1][k]&&w[i][k])
		{
			if(!f1[i]||a[k]>a[f1[i]])f3[i]=f2[i],f2[i]=f1[i],f1[i]=k;
			else if(!f2[i]||a[k]>a[f2[i]])f3[i]=f2[i],f2[i]=k;
			else if(!f3[i]||a[k]>a[f3[i]])f3[i]=k;
		}
	}
//	rep(1,n,i)printf("%d ",f1[i]);puts("");
	ll ans=0;
	rep(2,n,i)
	{
		rep(i+1,n,j)if(w[i][j])
		{
			int x[3]={f1[i],f2[i],f3[i]},y[3]={f1[j],f2[j],f3[j]};
			rep(0,2,b)rep(0,2,c)if(x[b]&&y[c]&&x[b]!=y[c]&&x[b]!=j&&y[c]!=i)ans=max(ans,0ll+a[i]+a[j]+a[x[b]]+a[y[c]]);
		}
	}
	printf("%lld\n",ans);
}
